CREATE MEMORY TABLE "PUBLIC"."DONATIONS"(
    "QUANTITY" INTEGER,
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 5) NOT NULL,
    "CATEGORY" CHARACTER VARYING(255),
    "DATE_ENTERED" CHARACTER VARYING(255),
    "ITEM_NAME" CHARACTER VARYING(255),
    "STATUS" CHARACTER VARYING(255)
);     
ALTER TABLE "PUBLIC"."DONATIONS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_2" PRIMARY KEY("ID");     
